}

// API DTO
public class OrderResponse {
    private Long orderId;
    private String customerName;
    private List<OrderItemDto> items;
    private BigDecimal total;
    // Only fields needed by API consumers
}

@Service
public class OrderService {
    @Transactional
    public Order createOrder(OrderRequest request) {
        Order order = orderRepository.save(new Order(request));
        paymentService.processPayment(order);
        inventoryService.reserveItems(order.getItems());
        return order;
    }
}

@ExtendWith(MockitoExtension.class)
class OrderServiceTest {
    @Mock
    private OrderRepository orderRepository;

    @Mock
    private PaymentService paymentService;

    @InjectMocks
    private OrderService orderService;

    @Test
    void shouldCreateOrderSuccessfully() {
        // Given
        OrderRequest request = new OrderRequest();
        Order expectedOrder = new Order();
        when(orderRepository.save(any())).thenReturn(expectedOrder);

        // When
        Order result = orderService.createOrder(request);

        // Then
        assertNotNull(result);
        verify(paymentService).processPayment(expectedOrder);
    }
}

@Test
void shouldProcessRefundSuccessfully() {
    // Arrange (Given)
    Order order = createTestOrder();
    when(paymentService.refund(any())).thenReturn(true);

    // Act (When)
    RefundResult result = orderService.processRefund(order.getId());

    // Assert (Then)
    assertTrue(result.isSuccessful());
    assertEquals(RefundStatus.COMPLETED, result.getStatus());
    verify(paymentService).refund(order.getPaymentId());
}

