practice.example:
@RestController
@RequestMapping("/api/orders")
public class OrderController {
    @GetMapping("/{id}")
    @PreAuthorize("hasRole('USER')")
    public Order getOrder(@PathVariable Long id) {
        return orderService.getOrder(id);
    }

    @DeleteMapping("/{id}")
    @PreAuthorize("hasRole('ADMIN')")
    public void deleteOrder(@PathVariable Long id) {
        orderService.deleteOrder(id);
    }
}

testing-immutable-records.problem:
// Legacy mutable class test pattern (DOES NOT WORK with records)
Order order = new Order();
order.setStatus(OrderStatus.PENDING);
order.setStatus(OrderStatus.COMPLETED);  // Modify state
assertEquals(OrderStatus.COMPLETED, order.getStatus());

testing-immutable-records.solution:
// Record immutability pattern - create new instances with modified values
Order order = new Order(1L, customer, items, OrderStatus.PENDING, LocalDateTime.now());

// To test status change, create a new instance with different status
Order completedOrder = order.withStatus(OrderStatus.COMPLETED);

assertEquals(OrderStatus.PENDING, order.getStatus());      // Original unchanged
assertEquals(OrderStatus.COMPLETED, completedOrder.getStatus());  // New instance

testing-immutable-records.with-method-pattern:
// Add "with" methods to records for creating modified copies
public record Order(
    Long id,
    Customer customer,
    List<OrderItem> items,
    OrderStatus status,
    LocalDateTime createdAt
) {
    // Legacy getter for backward compatibility
    public OrderStatus getStatus() { return status; }

    // "with" method for creating modified copies
    public Order withStatus(OrderStatus newStatus) {
        return new Order(id, customer, items, newStatus, createdAt);
    }

    // Add "with" methods for other fields as needed
    public Order withCustomer(Customer newCustomer) {
        return new Order(id, newCustomer, items, status, createdAt);
    }
}

testing-immutable-records.test-example:
@Test
void shouldTransitionOrderStatus() {
    // Arrange - create initial immutable order
    Order pendingOrder = new Order(
        1L,
        new Customer("John Doe", "john@example.com"),
        List.of(new OrderItem("Product A", 2, new BigDecimal("29.99"))),
        OrderStatus.PENDING,
        LocalDateTime.now()
    );

    // Act - create new instance with modified status
    Order processingOrder = pendingOrder.withStatus(OrderStatus.PROCESSING);
    Order completedOrder = processingOrder.withStatus(OrderStatus.COMPLETED);

    // Assert - verify each instance has correct state
    assertEquals(OrderStatus.PENDING, pendingOrder.getStatus());
    assertEquals(OrderStatus.PROCESSING, processingOrder.getStatus());
    assertEquals(OrderStatus.COMPLETED, completedOrder.getStatus());

    // Verify original order is unchanged (immutability)
    assertNotSame(pendingOrder, completedOrder);
}

jackson-serialization.example:
@Configuration
public class JacksonConfig {
    @Bean
    public Jackson2ObjectMapperBuilderCustomizer jacksonCustomizer() {
        return builder -> builder
            .visibility(PropertyAccessor.GETTER, Visibility.PUBLIC_ONLY)
            .visibility(PropertyAccessor.IS_GETTER, Visibility.PUBLIC_ONLY)
            .visibility(PropertyAccessor.FIELD, Visibility.NONE)
            .featuresToDisable(SerializationFeature.WRITE_DATES_AS_TIMESTAMPS);
    }
}
